// end of read input and construct graph g
vector<pair<int,int>> p(n - 2);
{
int index = 0;
auto g = groups(a);
forn(i, n)
if (i != a && i != b)
p[index++].first = g[i];
}
{
int index = 0;
auto g = groups(b);
forn(i, n)
if (i != a && i != b)
p[index++].second = g[i];
}
